local MainControlController = class("MainControlController", BaseController)

local function doGrab()
    local entityId = 0

    local player = PlayerManager:getClientPlayer()
    if player:isGrab() then
        return
    end

    if player then
        local boxExpand = player:getWidth() * GameConfig.adjustCoe * player:getScale()
        entityId = player.Player:catchEntity(boxExpand)
        LogUtil.log(string.format("player.Player:catchEntity entityId:%d boxExpand:%f Width:%f Scale:%f adjustCoe:%f",
                entityId, boxExpand, player:getWidth(), player:getScale(), GameConfig.adjustCoe))
    end

    if entityId == 0 then
        local data = DataBuilder.new():addParam("doGrab", "false"):getData()
        PacketSender:sendLuaCommonData("DoReport", data)
        return
    else
        local data = DataBuilder.new():addParam("doGrab", "true"):getData()
        PacketSender:sendLuaCommonData("DoReport", data)
    end

    --取消普通攻击按钮选中
    if GUIMainControl.selectMode ~= Define.SelectMode.NotSelect then
        GUIMainControl:onButtonSelect(GUIMainControl.selectMode)
    end

    PacketSender:getSender():sendBindEntity(player:getEntityId(), entityId, "s_hand_r", 0)

    player.property.catchEntityId = entityId
end

local function doPlace()
    local player = PlayerManager:getClientPlayer()
    if player == nil then
        return
    end

    if player.property.catchEntityId == 0 then
        return
    end

    PacketSender:getSender():sendUnbindEntity(player.property.catchEntityId)

    player.property.catchEntityId = 0
end

local function getActionId(flag)
    local actionId = -1
    if flag == Define.SelectMode.Equip then
        actionId = Define.ActionId.juzhong
    elseif flag == Define.SelectMode.Punch then
        actionId = Define.ActionId.quanji
    elseif flag == Define.SelectMode.Step then
        actionId = Define.ActionId.jiaocai
    end
    return actionId
end

local function onSkillGrabEnd()
    --local data = DataBuilder.new():addParam("skillId", -1):getData()
    --PacketSender:sendLuaCommonData("PlaySkill", data)

    local player = PlayerManager:getClientPlayer()
    if player:isGrab() then
        doPlace()
    else
        doGrab()
    end
end

function MainControlController:ctor()
end

function MainControlController:init()
end

function MainControlController:onClickScene(force)
    local player = PlayerManager:getClientPlayer()
    if not player or not player.property then
        return
    end

    if player.property.canAttack == false and GUIMainControl.selectMode ~= Define.SelectMode.Equip then
        return
    end

    if player.property.canWorkout == false and GUIMainControl.selectMode == Define.SelectMode.Equip then
        return
    end

    if GUIMainControl.isAttackCd == true then
        return
    end

    if GUIMainControl.autoWorkout and force == false then
        return
    end

    if GUIMainControl.selectMode == Define.SelectMode.NotSelect then
        return
    end

    if player:isEntityAlive() == false or player:isBeGrab() then
        return
    end

    if player then
        local cdTime = (GUIMainControl.selectMode == Define.SelectMode.Equip and GameConfig.attackCdTime or 1000)
        player.Player:setInsertUpperAction1(1000, cdTime, getActionId(GUIMainControl.selectMode))
    end

    --print("MainControlController:onClickScene " .. GUIMainControl.selectMode)

    if GUIMainControl.selectMode == Define.SelectMode.Equip then
        --ClientHelper.putIntPrefs("ArmSwingAnimationEnd", 24)
        if player.property.muscleMass < player.property.maxMuscleMass then
            PacketSender:sendLuaCommonData("DoWorkout", "")
            --print("DoWorkout " .. os.clock())
        else
            LogUtil.log("MainControlController:onClickScene GUIMainControl:showMuscleFullTips")
            GUIMainControl:showMuscleFullTips()
        end
    elseif GUIMainControl.selectMode == Define.SelectMode.Punch then
        --ClientHelper.putIntPrefs("ArmSwingAnimationEnd", 16)
        PacketSender:sendLuaCommonData("DoQuanJi", "")
    elseif GUIMainControl.selectMode == Define.SelectMode.Step then
        --ClientHelper.putIntPrefs("ArmSwingAnimationEnd", 20)
        PacketSender:sendLuaCommonData("DoJiaoCai", "")
    end

    GUIMainControl:onClickSceneCd(force)

    return false
end

function MainControlController:onClickScenePlayAction()
    return false
end

function MainControlController:doButtonSelect(flag)
    local player = PlayerManager:getClientPlayer()
    if player:isEntityAlive() == false then
        return
    end

    local fitnessEquipId = 0
    if GUIMainControl.selectMode == Define.SelectMode.Equip then
        fitnessEquipId = PlayerManager:getClientPlayer().property.fitnessEquipId
    end

    local params = {
        ItemId = fitnessEquipId,
        selectMode = GUIMainControl.selectMode,
    }
    local data = DataBuilder.new():fromTable(params):getData()
    PacketSender:sendLuaCommonData("ChangeHoldItemActor", data)
    LogUtil.log("MainControlController:doButtonSelect " .. flag)
end

