function MainControlController:onSkillGrab()
    --if GUIMainControl.isSkillCd == true then
    --    return
    --end

    local player = PlayerManager:getClientPlayer()
    if player:isEntityAlive() == false then
        return
    end

    player.Player:setInsertUpperAction1(1000, 1000, Define.ActionId.zhuaqu)

    self.grabTimer = LuaTimer:scheduleTimer(function()
        onSkillGrabEnd()
    end, 1000, 1)

    GUIMainControl:onSkillCd( GameConfig.SkillCd ,4)
end

return MainControlController